// Data Source 1: Manufacturing defects
const manufacturing = [
  { product: "Widget-X", defect: "Crack", previous: 18, current: 42 },
  { product: "Widget-Y", defect: "Misalignment", previous: 6, current: 9 }
];

// Data Source 2: Customer complaints
const complaints = [
  { product: "Widget-X", complaints: 27 },
  { product: "Widget-Y", complaints: 4 }
];

return [{ manufacturing, complaints }];

const results = [];

for (const item of items[0].json.manufacturing) {
  const complaint = items[0].json.complaints.find(c => c.product === item.product);

  const defectIncrease = item.current - item.previous;
  const defectIncreasePct = (defectIncrease / item.previous) * 100;

  let severity = "LOW";
  if (defectIncreasePct > 50 || (complaint && complaint.complaints > 20)) {
    severity = "HIGH";
  } else if (defectIncreasePct > 20) {
    severity = "MEDIUM";
  }

  if (severity !== "LOW") {
    results.push({
      product: item.product,
      defect: item.defect,
      previous_defects: item.previous,
      current_defects: item.current,
      complaints: complaint ? complaint.complaints : 0,
      severity
    });
  }
}

return results.map(r => ({ json: r }));

const alerts = items.map(i =>
  `Product ${i.json.product} shows emerging quality issues. Defect: ${i.json.defect}. Severity: ${i.json.severity}.`
);

return [{
  json: {
    message: alerts.join(" "),
    voice_response: alerts.join(" "),
    alert_count: alerts.length
  }
}];
